import './ExpansionPanel.scss';

import type { FC, MouseEventHandler } from 'react';
import React, { useEffect, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import type { ExpansionPanelProps } from './ExpansionPanel.types';
import { ExpansionPanelTitle } from './ExpansionPanelTitle';

export const ExpansionPanel: FC<ExpansionPanelProps> = ({
	open,
	title,
	description,
	subTitle,
	onOpen,
	onClose,
	className,
	titleClassName,
	bodyClassName,
	children,
	iconName,
	customButton,
	...props
}) => {
	const [_open, _setOpen] = useState<boolean | undefined>(open);

	useEffect(() => {
		if (_open !== open) {
			_setOpen(open);
		}
	}, [open]);

	const handleClick: MouseEventHandler = (event): void => {
		if (_open) {
			onClose?.(event);
		} else {
			onOpen?.(event);
		}
		_setOpen(prev => !prev);
	};

	return (
		<section {...props} className={classNames('dsb_expansion-panel', className)} data-testid="ExpansionPanel">
			<ExpansionPanelTitle
				open={_open}
				title={title}
				onClick={handleClick}
				subTitle={subTitle}
				description={description}
				iconName={iconName}
				customButton={customButton}
				className={classNames(titleClassName)}
			/>
			<div
				className={classNames(
					'dsb_expansion-panel-body',
					!_open && 'dsb_expansion-panel-body__collapsed',
					bodyClassName,
				)}
			>
				{children}
			</div>
		</section>
	);
};
